{
    "name": "detain/ip_vlan_manager",
    "type": "library",
    "description": "IP\/VLAN Management System",
    "keywords": [
        "ip",
        "vlan",
        "network"
    ],
    "license": "LGPL-2.1-only",
    "authors": [
        {
            "name": "Joe Huss",
            "homepage": "https:\/\/my.interserver.net\/"
        }
    ],
    "require": {
        "php": ">=5.6.0",
        "pear/net_ipv4": "dev-trunk",
        "mlocati/ip-lib": "dev-main"
    },
    "require-dev": {
        "phpunit/phpunit": ">=4.8.35, <6.0.0",
        "phpunit/phpunit-mock-objects": "*"
    },
    "suggest": {
        "s1lentium/iptools": "dev-master"
    },
    "autoload": {
        "psr-4": {
            "Detain\\IpVlanManager\\": "src/"
        }
    },
    "minimum-stability": "dev"
}

#!/usr/bin/env php
<?php


define('DEBUG', false);
$GLOBALS['webpage'] = false;

require_once __DIR__ .'/../../../../include/functions.inc.php';
function_requirements('update_switch_ports');
update_switch_ports(true, isset($_SERVER['argv'][1]) && in_array(strtolower($_SERVER['argv'][1]), ['false', 'no', '0']) ? false : true);
